import { NextResponse } from 'next/server';
import { prisma } from '@/lib/prisma';

export async function POST(req: Request, { params }: { params: Promise<{ id: string }> }) {
    try {
        const { id } = await params;
        const { answers, studentName } = await req.json();

        if (!studentName || !id) {
            return NextResponse.json({ error: 'Missing required fields' }, { status: 400 });
        }

        // Check if user exists (we expect them to be logged in now, so strict check?)
        // For now, let's assume the frontend sends 'username' as 'studentName' prop for compat, 
        // OR we update frontend to send 'username'. Let's stick to matching unique identifiers.
        // The previous code created a student if not found. With password auth, we shouldn't auto-create.
        // But for this step, let's just find by username.
        const user = await prisma.user.findUnique({ where: { username: studentName } });

        if (!user) {
            return NextResponse.json({ error: 'User not found. Please login.' }, { status: 404 });
        }

        // Check if already attempted
        const existingAttempt = await prisma.attempt.findFirst({
            where: {
                userId: user.id,
                testId: id
            }
        });

        if (existingAttempt) {
            return NextResponse.json({ error: 'You have already attempted this test.' }, { status: 400 });
        }

        // Calculate Score
        const test = await prisma.test.findUnique({
            where: { id: id },
            include: { questions: true }
        });

        if (!test) return NextResponse.json({ error: 'Test not found' }, { status: 404 });

        let score = 0;

        // We need to parse answers which come as a map { qId: optionIndex }

        test.questions.forEach(question => {
            const selectedOption = answers[question.id];

            // If question was answered
            if (selectedOption !== undefined && selectedOption !== null) {
                if (Number(selectedOption) === question.correctAnswer) {
                    score += test.correctMarks;
                } else {
                    score += test.incorrectMarks;
                }
            }
        });

        const attempt = await prisma.attempt.create({
            data: {
                testId: id,
                userId: user.id,
                score,
                answers: JSON.stringify(answers)
            }
        });

        return NextResponse.json({ success: true, score });

    } catch (error) {
        console.error(error);
        return NextResponse.json({ error: 'Submission failed' }, { status: 500 });
    }
}
